const moveQueueItemsToBatchedQueue = `-- name: MoveQueueItemsToBatchedQueue :many
WITH locked_qis AS (
    SELECT
        qi.id, qi.tenant_id, qi.queue, qi.task_id, qi.task_inserted_at, qi.external_id, qi.action_id, qi.step_id, qi.workflow_id, qi.workflow_run_id, qi.schedule_timeout_at, qi.step_timeout, qi.priority, qi.sticky, qi.desired_worker_id, qi.retry_count, qi.desired_worker_label, qi.batch_key
    FROM
        v1_queue_item qi
    JOIN
        v1_step_batch_config sbc ON sbc.step_id = qi.step_id
    WHERE
        qi.id = ANY($1::bigint[])
        AND sbc.batch_max_size >= 1
    ORDER BY
        qi.id ASC
    FOR UPDATE
), inserted AS (
    INSERT INTO v1_batched_queue_item (
        tenant_id,
        queue,
        task_id,
        task_inserted_at,
        external_id,
        action_id,
        step_id,
        workflow_id,
        workflow_run_id,
        schedule_timeout_at,
        step_timeout,
        priority,
        sticky,
        desired_worker_id,
        retry_count,
        batch_key,
        inserted_at,
        payload_size
    )
    SELECT
        lqi.tenant_id,
        lqi.queue,
        lqi.task_id,
        lqi.task_inserted_at,
        lqi.external_id,
        lqi.action_id,
        lqi.step_id,
        lqi.workflow_id,
        lqi.workflow_run_id,
        lqi.schedule_timeout_at,
        lqi.step_timeout,
        lqi.priority,
        lqi.sticky,
        lqi.desired_worker_id,
        lqi.retry_count,
        COALESCE(BTRIM(lqi.batch_key), ''),
        CURRENT_TIMESTAMP,
        COALESCE(OCTET_LENGTH(t.input::text), 0)
    FROM
        locked_qis lqi
    LEFT JOIN v1_task t ON t.id = lqi.task_id AND t.inserted_at = lqi.task_inserted_at
    ON CONFLICT (task_id, task_inserted_at, retry_count) DO NOTHING
    RETURNING task_id
)
DELETE FROM v1_queue_item
WHERE id IN (SELECT id FROM locked_qis)
RETURNING id
`

